// ══════════════════════════════════════════════════════════════════════════════
// APP ROOT
// ══════════════════════════════════════════════════════════════════════════════
export default function App() {
  const [page, setPage] = useState("accueil");
  const [activeCat, setActiveCat] = useState(null);
  const [cart, setCart] = useState([]);
  const [lastOrder, setLastOrder] = useState(null);

  function goHome() { setPage("accueil"); setActiveCat(null); }

  function selectCategory(catId) {
    setActiveCat(catId);
    setPage("produits");
  }

  function handleBuyNow() {
    setPage("commande");
  }

  async function handleConfirm(order) {
    setLastOrder(order);
    setCart([]);
    setPage("confirmation");
    // Enregistrer dans Supabase
    try {
      await saveCommande(order);
    } catch(e) {
      console.error("Erreur Supabase:", e);
    }
  }

  if (page === "accueil") return (
    <PageAccueil
      cart={cart} setCart={setCart}
      onSelectCategory={selectCategory}
      onGoToCart={() => setPage("panier")}
      onBuyNow={handleBuyNow}
    />
  );

  if (page === "produits") return (
    <PageProduits
      activeCat={activeCat} setActiveCat={setActiveCat}
      cart={cart} setCart={setCart}
      onHome={goHome}
      onGoToCart={() => setPage("panier")}
      onBuyNow={handleBuyNow}
    />
  );

  if (page === "panier") return (
    <PagePanier
      cart={cart} setCart={setCart}
      onBack={() => setPage(activeCat ? "produits" : "accueil")}
      onOrder={() => setPage("commande")}
    />
  );

  if (page === "commande") return (
    <PageCommande cart={cart} onBack={() => setPage("panier")} onConfirm={handleConfirm} />
  );

  if (page === "confirmation") return (
    <PageConfirmation order={lastOrder} onHome={goHome} />
  );
}
